import { PriorityQueue } from 'typescript-collections';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, s, e] of edges) {
        adj[u].push({ v, s, e });
    }

    // Dijkstra's algorithm with priority queue
    const dist = new Array(n).fill(-1);
    dist[0] = 0;

    const pq = new PriorityQueue((a, b) => a.time - b.time);
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node, time } = pq.dequeue();
        if (node === n - 1) break;

        // Try to take each edge from the current node
        for (const { v, s, e } of adj[node]) {
            // Check if we can use this edge at the current time
            if (time >= s && time <= e) {
                // We can take this edge, move to the next node at time e
                const newTime = e;
                if (dist[v] === -1 || newTime < dist[v]) {
                    dist[v] = newTime;
                    pq.enqueue({ node: v, time: newTime });
                }
            } else {
                // If the edge is not available at current time, we can wait
                // Wait until the start of the edge
                const waitTime = Math.max(s, time);
                if (dist[v] === -1 || waitTime < dist[v]) {
                    dist[v] = waitTime;
                    pq.enqueue({ node: v, time: waitTime });
                }
            }
        }

        // Also consider staying at the current node
        if (dist[node] !== -1) {
            const newTime = time + 1;
            if (dist[node] === -1 || newTime < dist[node]) {
                dist[node] = newTime;
                pq.enqueue({ node: node, time: newTime });
            }
        }
    }

    return dist[n - 1] === -1 ? -1 : dist[n - 1];
}

